dslRuleAfterChange:
// Hypothetical DSL extension for multi-statement patterns and replacements
block {
    $img = new org.eclipse.swt.graphics.Image($display, $width, $height);
    $gc = new org.eclipse.swt.graphics.GC($img);
    $gc.setBackground($color);
    $gc.fillRectangle($x, $y, $width, $height);
    $gc.dispose();
}
=>
block {
    final org.eclipse.swt.graphics.ImageGcDrawer $drawer = (gc, drawableWidth, drawableHeight) -> {
        gc.setBackground($color);
        gc.fillRectangle($x, $y, drawableWidth, drawableHeight);
    };
    $img = new org.eclipse.swt.graphics.Image($display, $drawer, $width, $height);
}
;;
